import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../App';
import api from '../api';

const LOGIN_T = {
  en: {
    title: 'Welcome back',
    sub: 'Sign in to your MediHelp account',
    email: 'Email Address', password: 'Password',
    signin: 'Sign In', signing: 'Signing in…',
    noAccount: 'No account?', create: 'Create one free',
    demo: 'Demo admin',
    langLabel: 'KW',   // button label to switch TO Swahili
  },
  sw: {
    title: 'Karibu tena',
    sub: 'Ingia kwenye akaunti yako ya MediHelp',
    email: 'Anwani ya Barua Pepe', password: 'Nenosiri',
    signin: 'Ingia', signing: 'Inaingia…',
    noAccount: 'Huna akaunti?', create: 'Fungua bure',
    demo: 'Msimamizi wa demo',
    langLabel: 'EN',
  }
};

export default function Login() {
  const { login } = useAuth();
  const navigate = useNavigate();
  const [form, setForm] = useState({ email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [lang, setLang] = useState('en');
  const t = LOGIN_T[lang];

  const set = k => e => setForm({ ...form, [k]: e.target.value });

  const handleSubmit = async e => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      const res = await api.post('/api/login', form);
      login(res.data.user, res.data.token);
      navigate(res.data.user.role === 'ADMIN' ? '/admin' : '/dashboard');
    } catch (err) {
      setError(err.response?.data?.error || (lang==='sw'?'Imeshindwa. Angalia tena.':'Login failed. Check your credentials.'));
    } finally { setLoading(false); }
  };

  return (
    <div style={{ minHeight: 'calc(100vh - 64px)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '2rem 1.25rem', background: 'linear-gradient(135deg, #f0fdf4 0%, #dcfce7 100%)' }}>
      <div className="card fade-up" style={{ width: '100%', maxWidth: 420 }}>

        {/* Language toggle */}
        <div style={{ display:'flex', justifyContent:'flex-end', marginBottom:8 }}>
          <button className="lang-toggle" onClick={() => setLang(lang==='en'?'sw':'en')}
            style={{ background:'#f0fdf4', border:'1.5px solid #bbf7d0', borderRadius:8, padding:'4px 12px', fontSize:'0.78rem', fontWeight:700, cursor:'pointer', color:'#15803d', display:'flex', alignItems:'center', gap:5 }}>
            <span style={{fontSize:'1rem'}}>{lang==='en'?'🇰🇪':'🇬🇧'}</span>{t.langLabel}
          </button>
        </div>

        <div style={{ textAlign: 'center', marginBottom: '1.5rem' }}>
          <div style={{ fontSize: '2rem', marginBottom: 8 }}>👋</div>
          <h2 style={{ fontSize: '1.6rem', marginBottom: 4 }}>{t.title}</h2>
          <p style={{ color: '#6b7280', fontSize: '0.875rem' }}>{t.sub}</p>
        </div>

        {error && <div className="alert alert-error">{error}</div>}

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label className="form-label">{t.email}</label>
            <input type="email" className="form-input" value={form.email} onChange={set('email')} placeholder="you@email.com" required />
          </div>
          <div className="form-group">
            <label className="form-label">{t.password}</label>
            <input type="password" className="form-input" value={form.password} onChange={set('password')} placeholder="••••••••" required />
          </div>
          <button type="submit" className="btn btn-primary" disabled={loading} style={{ width: '100%', justifyContent: 'center', padding: '0.75rem', marginTop: 8 }}>
            {loading ? <><span className="spinner" style={{ width: 16, height: 16 }} /> {t.signing}</> : t.signin}
          </button>
        </form>

        <p style={{ textAlign: 'center', marginTop: '1.25rem', fontSize: '0.875rem', color: '#6b7280' }}>
          {t.noAccount} <Link to="/register" style={{ color: '#16a34a', fontWeight: 600 }}>{t.create}</Link>
        </p>

        <div style={{ marginTop: '1rem', padding: '0.75rem', background: '#f0fdf4', borderRadius: 10, fontSize: '0.78rem', color: '#6b7280', textAlign: 'center' }}>
          {t.demo}: <strong>admin@medihelp.ke</strong> / <strong>admin123</strong>
        </div>
      </div>
    </div>
  );
}
